// GetMsftProviders returns the Msft_Providers instance identified by its key
// properties, or wmi.ErrNotFound.
func GetMsftProviders(svc *wmi.Service, hostingGroup string, hostingSpecification uint32, locale string, namespace string, transactionIdentifier string, user string, provider string) (*MsftProviders, error) {
	where := "HostingGroup = " + wmi.WQLValue(hostingGroup) +
		" AND " + "HostingSpecification = " + wmi.WQLValue(hostingSpecification) +
		" AND " + "Locale = " + wmi.WQLValue(locale) +
		" AND " + "Namespace = " + wmi.WQLValue(namespace) +
		" AND " + "TransactionIdentifier = " + wmi.WQLValue(transactionIdentifier) +
		" AND " + "User = " + wmi.WQLValue(user) +
		" AND " + "provider = " + wmi.WQLValue(provider)
	return QueryOneMsftProviders(svc, where)
}

